 26→import { SearchDropdown } from '../search_bar/search_dropdown';
 27→import './settings_view.scss';
 28→
 29→type SettingsTab = 'general' | 'extensions' | 'advanced';
 30→
 31→const SETTINGS_TABS: SettingsTab[] = [
 32→  'general',
 33→  'extensions',
 34→  'advanced',
 35→];
 36→
 37→function isSettingsTab(value: string): value is SettingsTab {
 38→  return SETTINGS_TABS.includes(value as SettingsTab);
 39→}
 40→
 41→interface GeneralSettings {
 42→  appearance: string;
 43→  windowPosition: string;
 44→  windowWidth: string;
 45→  showRecentApps: boolean;
 46→  showDock: boolean;
 47→  fontSize: string;
 48→}
 49→
 50→const SETTINGS_STORAGE_KEY = 'settings-general';
 51→const EXTENSIONS_STORAGE_KEY = 'settings-extensions';
 52→
 53→const DEFAULT_SETTINGS: GeneralSettings = {
 54→  appearance: 'dark',
 55→  windowPosition: 'top-third',
 56→  windowWidth: 'medium',
 57→  showRecentApps: true,
 58→  showDock: true,
 59→  fontSize: 'default',
 60→};
 61→
 62→function isGeneralSettings(value: unknown): value is GeneralSettings {
 63→  if (!isRecord(value)) return false;
 64→  return (
 65→    typeof value.appearance === 'string' &&
 66→    typeof value.windowWidth === 'string' &&
 67→    typeof value.showRecentApps === 'boolean' &&
 68→    typeof value.showDock === 'boolean' &&
 69→    typeof value.fontSize === 'string' &&
 70→    (value.windowPosition === undefined || typeof value.windowPosition === 'string')
 71→  );
 72→}
 73→
 74→function loadSettings(themePreference: string): GeneralSettings {
 75→  const stored = storageGet(SETTINGS_STORAGE_KEY, isGeneralSettings);
 76→  if (stored)
 77→    return {
 78→      ...stored,
 79→      appearance: themePreference,
 80→    };
 81→  return {
 82→    ...DEFAULT_SETTINGS,
 83→    appearance: themePreference,
 84→  };
 85→}
 86→
 87→function loadExtensions(): ExtensionEntry[] {
 88→  const states = storageGet(EXTENSIONS_STORAGE_KEY, isBooleanRecord);
 89→  return MOCK_EXTENSIONS.map(ext => ({
 90→    ...ext,
 91→    enabled: states ? (states[ext.id] ?? ext.enabled) : ext.enabled,
 92→  }));
 93→}
