680→          showHUD({
681→            icon: <SuccessHUDIcon />,
682→            title: 'Settings Reset',
683→          });
684→        },
685→      },
686→      dismissAction: {
687→        label: 'Cancel',
688→        style: 'cancel',
689→        onAction: () => {},
690→      },
691→    });
692→  }, [
693→    confirmAlert,
694→    showHUD,
695→    setTheme,
696→  ]);
697→
698→  const toggleActions = useCallback(() => {
699→    setActionsOpen(prev => !prev);
700→  }, []);
701→
702→  const closeActions = useCallback(() => {
703→    setActionsOpen(false);
704→  }, []);
705→
706→  useKeyboardShortcut(
707→    {
708→      key: 'k',
709→      meta: true,
710→    },
711→    toggleActions,
712→  );
713→
714→  const dropdownSections: DropdownSection[] = useMemo(() => {
715→    const sections: DropdownSection[] = [
716→      {
717→        title: 'Navigation',
718→        actions: [
719→          {
720→            label: 'General',
721→            onClick: () => {
722→              setActiveTab('general');
723→              setActionsOpen(false);
724→            },
725→          },
726→          {
727→            label: 'Extensions',
728→            onClick: () => {
729→              setActiveTab('extensions');
730→              setActionsOpen(false);
731→            },
732→          },
733→          {
734→            label: 'Advanced',
735→            onClick: () => {
736→              setActiveTab('advanced');
737→              setActionsOpen(false);
738→            },
739→          },
740→        ],
741→      },
742→    ];
743→
744→    if (activeTab === 'advanced') {
745→      sections.push({
746→        title: 'Actions',
747→        actions: [
748→          {
749→            label: 'Export Settings',
750→            onClick: handleExport,
751→          },
752→          {
753→            label: 'Import Settings',
754→            onClick: handleImport,
755→          },
756→          {
757→            label: 'Clear Cache',
758→            onClick: handleClearCache,
759→          },
760→          {
761→            label: 'Reset All Settings',
