    value: 'dark',
  },
  {
    label: 'Light',
    value: 'light',
  },
  {
    label: 'System',
    value: 'system',
  },
];

const WINDOW_WIDTH_OPTIONS = [
  {
    label: 'Small (680px)',
    value: 'small',
  },
  {
    label: 'Medium (750px)',
    value: 'medium',
  },
  {
    label: 'Large (820px)',
    value: 'large',
  },
];

const WINDOW_POSITION_OPTIONS = [
  {
    label: 'Top Third',
    value: 'top-third',
  },
  {
    label: 'Center',
    value: 'center',
  },
];

const FONT_SIZE_OPTIONS = [
  {
    label: 'Small',
    value: 'small',
  },
  {
    label: 'Default',
    value: 'default',
  },
  {
    label: 'Large',
    value: 'large',
  },
];

function ToggleSwitch({
  checked,
  onChange,
  label,
}: {
  checked: boolean;
  onChange: (checked: boolean) => void;
  label: string;
}) {
  return (
    <label className="settings-toggle" onClick={e => e.stopPropagation()}>
      <input
        type="checkbox"
        className="settings-toggle__input"
        checked={checked}
        onChange={e => onChange(e.target.checked)}
        aria-label={label}
      />
      <div className="settings-toggle__track" />
      <div className="settings-toggle__knob" />
    </label>
  );
}

function SuccessHUDIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
