  return (
    <div className="form">
      <div className="form__fields">
        <FormDropdown
          label="Appearance"
          value={settings.appearance}
          onChange={v =>
            onSettingsChange({
              ...settings,
              appearance: v,
            })
          }
          options={APPEARANCE_OPTIONS}
        />
        <FormDropdown
          label="Window Position"
          value={settings.windowPosition}
          onChange={v => {
            onSettingsChange({
              ...settings,
              windowPosition: v,
